"""AT&T Gateway client with version-aware operations"""

import hashlib
import logging

import requests
import urllib3

from . import parser, version

urllib3.disable_warnings(urllib3.exceptions.InsecureRequestWarning)

log = logging.getLogger(__name__)


class ATTGateway:
    """Client for interacting with AT&T BGW320-500 gateway.

    Handles:
    - Authentication (nonce + MD5 challenge)
    - Firmware version detection
    - Version-specific handler selection
    - Session management
    """

    def __init__(self, host, password):
        """Initialize gateway client.

        Args:
            host: Gateway IP address or hostname
            password: Gateway admin password
        """
        self.host = host
        self.base = f"https://{host}"
        self.password = password
        self.session = requests.Session()
        self.session.verify = False

        self.firmware_version = None
        self.handler = None
        self._authenticated = False

    def login(self):
        """Authenticate with the gateway using nonce+MD5 challenge.

        Returns:
            True if login successful, False otherwise

        Raises:
            RuntimeError: If login fails
        """
        try:
            # First request establishes session cookie
            r = self.session.get(f"{self.base}/cgi-bin/ipalloc.ha", allow_redirects=False, timeout=10)

            # Second request gets the login form with nonce
            r = self.session.get(f"{self.base}/cgi-bin/ipalloc.ha", timeout=10)

            # Extract nonce
            nonce = parser.extract_nonce(r.text)
            if not nonce:
                raise RuntimeError("Could not extract nonce from login page")

            # Calculate MD5(password + nonce)
            hash_input = self.password + nonce
            hashpwd = hashlib.md5(hash_input.encode()).hexdigest()
            stars = "*" * len(self.password)

            # Submit login form
            r = self.session.post(
                f"{self.base}/cgi-bin/login.ha",
                data={
                    "nonce": nonce,
                    "password": stars,
                    "hashpassword": hashpwd,
                    "Continue": "Continue",
                },
                allow_redirects=False,
                timeout=10
            )

            # Check if login was successful (302 redirect not to login.ha)
            if r.status_code != 302 or "login.ha" in r.headers.get("Location", ""):
                raise RuntimeError(
                    f"Login failed: status={r.status_code} "
                    f"location={r.headers.get('Location', 'none')}"
                )

            log.info("Successfully authenticated to gateway")
            self._authenticated = True

            # Now detect firmware version
            self.detect_and_set_handler()

            return True

        except Exception as e:
            log.error(f"Login failed: {e}")
            raise

    def detect_and_set_handler(self):
        """Detect firmware version and set appropriate handler.

        Should be called after successful login.
        """
        if not self._authenticated:
            log.warning("Attempting version detection without authentication")

        # Detect firmware version
        self.firmware_version = version.detect_firmware_version(self)

        if not self.firmware_version:
            log.warning("Could not detect firmware version, using default handler")
            version.warn_unknown_version("unknown")
            self.handler = version.get_handler_class(None)()
            return

        # Check for version changes
        changed, previous_version = version.check_version_change(self.firmware_version)

        if changed:
            # Firmware changed - log prominently
            log.warning("FIRMWARE VERSION CHANGED - taking automatic backup")
            # TODO: Trigger automatic backup when backup module is implemented

        # Get appropriate handler
        handler_class = version.get_handler_class(self.firmware_version)
        self.handler = handler_class()

        # Check if this is a known version
        handler_name, version_info = version.match_version_to_handler(self.firmware_version)
        if not handler_name:
            version.warn_unknown_version(self.firmware_version)

        # Save version to cache
        version.save_cached_version(self.firmware_version)

        log.info(f"Using handler: {self.handler.__class__.__name__} for firmware {self.firmware_version}")

    def get_page(self, page_path):
        """Fetch a page from the gateway.

        Args:
            page_path: Path to page (e.g., "/cgi-bin/dhcpserver.ha")

        Returns:
            Response object

        Raises:
            RuntimeError: If not authenticated or page fetch fails
        """
        if not self._authenticated:
            raise RuntimeError("Not authenticated - call login() first")

        try:
            r = self.session.get(f"{self.base}{page_path}", timeout=10)

            # Check if session expired
            if "Access Code Required" in r.text or "login.ha" in r.url:
                raise RuntimeError("Session expired - need to re-authenticate")

            return r

        except Exception as e:
            log.error(f"Failed to fetch {page_path}: {e}")
            raise

    def post_form(self, page_path, form_data):
        """Submit a form to the gateway.

        Args:
            page_path: Path to post to (e.g., "/cgi-bin/dhcpserver.ha")
            form_data: Dictionary of form fields

        Returns:
            Response object

        Raises:
            RuntimeError: If not authenticated or post fails
        """
        if not self._authenticated:
            raise RuntimeError("Not authenticated - call login() first")

        try:
            r = self.session.post(
                f"{self.base}{page_path}",
                data=form_data,
                timeout=10
            )

            return r

        except Exception as e:
            log.error(f"Failed to post to {page_path}: {e}")
            raise

    def get_dhcp_config(self):
        """Get current DHCP configuration.

        Returns:
            Dictionary with DHCP configuration
        """
        if not self.handler:
            raise RuntimeError("No handler set - call login() first")

        page_path = self.handler.get_dhcp_page_path()
        response = self.get_page(page_path)

        return self.handler.parse_dhcp_page(response.text)

    def get_ip_allocations(self):
        """Get current IP allocation table.

        Returns:
            Dictionary with IP allocations
        """
        if not self.handler:
            raise RuntimeError("No handler set - call login() first")

        page_path = self.handler.get_ipalloc_page_path()
        response = self.get_page(page_path)

        return self.handler.parse_ipalloc_page(response.text)

    def update_dhcp_config(self, public_subnet=None, private_lan=None):
        """Update DHCP configuration.

        Args:
            public_subnet: Dictionary with public subnet settings to change
            private_lan: Dictionary with private LAN settings to change

        Returns:
            True if update successful
        """
        if not self.handler:
            raise RuntimeError("No handler set - call login() first")

        page_path = self.handler.get_dhcp_page_path()

        # Get current page
        response = self.get_page(page_path)

        # Build form data
        form_data = self.handler.build_dhcp_form_data(
            response.text,
            public_subnet_config=public_subnet,
            private_lan_config=private_lan
        )

        # Submit
        log.info(f"Submitting DHCP configuration changes to {page_path}")
        response = self.post_form(page_path, form_data)

        # Check for success
        if "Changes saved" in response.text or response.status_code in (200, 302):
            log.info("DHCP configuration updated successfully")
            return True
        else:
            log.error("DHCP configuration update may have failed (no 'Changes saved' confirmation)")
            return False

    def allocate_ip(self, mac_address):
        """Allocate a fixed IP for a MAC address.

        Args:
            mac_address: MAC address to allocate (e.g., "bc:24:11:8f:08:b4")

        Returns:
            True if allocation successful
        """
        if not self.handler:
            raise RuntimeError("No handler set - call login() first")

        page_path = self.handler.get_ipalloc_page_path()

        # Get current page
        response = self.get_page(page_path)

        # Build form data
        form_data = self.handler.build_ipalloc_form_data(response.text, mac_address)

        # Submit
        log.info(f"Allocating IP for MAC {mac_address}")
        response = self.post_form(page_path, form_data)

        # Check for success
        if "Fixed Allocation" in response.text or "Changes saved" in response.text:
            log.info(f"Successfully allocated IP for {mac_address}")
            return True
        else:
            log.error(f"IP allocation for {mac_address} may have failed")
            return False
